+    pub fn follows(&self, other: &Self, other_id: &ObjectId) -> bool {
+        // Use checked_add to prevent overflow when other.seq is u64::MAX
+        other
+            .seq
+            .checked_add(1)
+            .is_some_and(|next_seq| self.seq == next_seq)
+            && self.prev.as_ref() == Some(other_id)
     }

